      industryAiReviewedAt: timestamp("industry_ai_reviewed_at"),
      industryAiStatus: industryAIStatusEnum("industry_ai_status"),
      annualRevenue: numeric("annual_revenue"),
      // Removed precision to allow deployment
      minAnnualRevenue: numeric("min_annual_revenue"),
      // Range minimum for revenue
      maxAnnualRevenue: numeric("max_annual_revenue"),
      // Range maximum for revenue
      revenueRange: revenueRangeEnum("revenue_range"),
