      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      leadId: varchar("lead_id").notNull().references(() => leads.id, { onDelete: "cascade" }),
      tagId: varchar("tag_id").notNull().references(() => leadTags.id, { onDelete: "cascade" }),
