      aiValidationResult: jsonb("ai_validation_result"),
      // Full AI analysis JSON from OpenAI Vision
      validationConfidence: numeric("validation_confidence", { precision: 5, scale: 2 }),
      // 0-100 confidence score
      extractedData: jsonb("extracted_data"),
      // {name, company, title} extracted by AI
      // On-Call Verification Path
      verifiedContactId: varchar("verified_contact_id").references(() => contacts.id),
      // New contact created during on-call verification
