    callQualityRecords = pgTable("call_quality_records", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      callSessionId: varchar("call_session_id").references(() => callSessions.id, { onDelete: "cascade" }).notNull(),
      dialerCallAttemptId: varchar("dialer_call_attempt_id").references(() => dialerCallAttempts.id, { onDelete: "cascade" }),
      campaignId: varchar("campaign_id").references(() => campaigns.id, { onDelete: "set null" }),
      contactId: varchar("contact_id").references(() => contacts.id, { onDelete: "set null" }),
      // Quality metrics
      overallQualityScore: integer("overall_quality_score"),
      // 0-100
      engagementScore: integer("engagement_score"),
      // 0-100
      clarityScore: integer("clarity_score"),
      // 0-100
      empathyScore: integer("empathy_score"),
      // 0-100
      objectionHandlingScore: integer("objection_handling_score"),
      // 0-100
      qualificationScore: integer("qualification_score"),
      // 0-100
      closingScore: integer("closing_score"),
      // 0-100
      // Conversation intelligence
      sentiment: text("sentiment"),
      // positive | neutral | negative
      engagementLevel: text("engagement_level"),
      // high | medium | low
      identityConfirmed: boolean("identity_confirmed"),
      qualificationMet: boolean("qualification_met"),
      // Analysis results (stored as JSON for flexibility)
      issues: jsonb("issues"),
      // Array of {type, severity, description, evidence, recommendation}
      recommendations: jsonb("recommendations"),
      // Array of {category, currentBehavior, suggestedChange, expectedImpact}
      breakdowns: jsonb("breakdowns"),
      // Array of {type, description, moment, recommendation}
      promptUpdates: jsonb("prompt_updates"),
      // Array of {category, change, rationale, priority}
      performanceGaps: jsonb("performance_gaps"),
      // Array of gap descriptions
      nextBestActions: jsonb("next_best_actions"),
      // Array of recommended actions
      // Campaign alignment
      campaignAlignmentScore: integer("campaign_alignment_score"),
      contextUsageScore: integer("context_usage_score"),
      talkingPointsCoverageScore: integer("talking_points_coverage_score"),
      missedTalkingPoints: jsonb("missed_talking_points"),
      // Array of strings
      // Flow compliance
      flowComplianceScore: integer("flow_compliance_score"),
      missedSteps: jsonb("missed_steps"),
      // Array of strings
      flowDeviations: jsonb("flow_deviations"),
      // Array of strings
      // Disposition accuracy
      assignedDisposition: text("assigned_disposition"),
      expectedDisposition: text("expected_disposition"),
      dispositionAccurate: boolean("disposition_accurate"),
      dispositionNotes: jsonb("disposition_notes"),
      // Array of notes
      // Transcript info
      transcriptLength: integer("transcript_length"),
      transcriptTruncated: boolean("transcript_truncated"),
      fullTranscript: text("full_transcript"),
      // Analysis metadata
      analysisModel: text("analysis_model"),
      // Model used for analysis
      analysisStage: text("analysis_stage"),
      // realtime | post_call
      interactionType: text("interaction_type"),
      // live_call | test_call | simulation
      analyzedAt: timestamp("analyzed_at"),
      // Showcase fields — pinned best-agent-performance calls for client demos
      isShowcase: boolean("is_showcase").default(false),
      showcaseCategory: text("showcase_category"),
      // objection_handling | professional_close | engagement_mastery | difficult_situation | perfect_flow | empathetic_response
      showcaseNotes: text("showcase_notes"),
      showcasedAt: timestamp("showcased_at"),
      showcasedBy: varchar("showcased_by").references(() => users.id, { onDelete: "set null" }),
      // Timestamps
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    }, (table) => ({
      callSessionIdx: index("call_quality_records_call_session_idx").on(table.callSessionId),
      dialerAttemptIdx: index("call_quality_records_dialer_attempt_idx").on(table.dialerCallAttemptId),
      campaignIdx: index("call_quality_records_campaign_idx").on(table.campaignId),
      contactIdx: index("call_quality_records_contact_idx").on(table.contactId),
      scoreIdx: index("call_quality_records_score_idx").on(table.overallQualityScore),
      createdAtIdx: index("call_quality_records_created_at_idx").on(table.createdAt),
      showcaseIdx: index("call_quality_records_showcase_idx").on(table.isShowcase)
    }));
