      intentScore: integer("intent_score"),
      // 0-100
      leadSource: varchar("lead_source", { length: 255 }),
      decisionMakers: jsonb("decision_makers").$type(),
      touchpointLog: jsonb("touchpoint_log").$type(),
      // Intelligent Sales System - Scoring Fields (Current State)
      engagementScore: integer("engagement_score").default(0),
      // 0-100: Email opens, replies, meeting attendance
      fitScore: integer("fit_score").default(0),
      // 0-100: Company size, industry match, role alignment
      stageProbability: integer("stage_probability").default(0),
      // 0-100: Likelihood of current stage success
      nextActionAiSuggestion: text("next_action_ai_suggestion"),
      // AI-recommended next action
      lastActivityAt: timestamp("last_activity_at", { withTimezone: true }),
      // Most recent interaction
